export function toggleReferenceGrid() {
    const existing = document.getElementById("referenceGrid");
    if (existing) {
        existing.remove();
    } else {
        const gridContainer = document.querySelector(".grid-container");
        gridContainer.insertAdjacentHTML("beforeend", REFERENCE_GRID_HTML);
    }
}